#!/usr/bin/env python3
"""Layout update: compact stats, two-column vendors/checklist"""
import base64, os, sys
if not os.path.exists("frontend/src/pages"):
    print("Error: Run from ~/seller-portal"); sys.exit(1)
data = ""
content = base64.b64decode(data)
with open("frontend/src/pages/ClientDashboard.jsx", "wb") as f:
    f.write(content)
print(f"  Updated: ClientDashboard.jsx ({len(content):,} bytes)")
print()
print("Now run:")
print('  git add -A && git commit -m "Pre-market layout: compact stats, vendors left, checklist right" && git push')
